import { computed } from 'vue'
import { storeToRefs } from 'pinia'
import { useAuthStore } from '~/stores/auth.js'

export function useNavLinks(handleLogout) {
  const { isAuthenticated, isAdmin } = storeToRefs(useAuthStore())

  const navLinks = computed(() => {
    const links = [
      { to: '/about',   labelKey: 'nav.about' },
      { to: '/contact', labelKey: 'nav.contact' },
      { to: '/sanakenno', labelKey: 'nav.sanakenno' },
    ]
    if (isAuthenticated.value) {
      links.push({ to: '/recipes', labelKey: 'nav.recipes' })
    }
    if (isAdmin.value) {
      links.push({ to: '/admin', labelKey: 'nav.admin' })
    }
    if (isAuthenticated.value) {
      links.push({ to: '/login', labelKey: 'nav.logout', action: handleLogout })
    } else {
      links.push({ to: '/login', labelKey: 'nav.login' })
    }
    return links
  })

  return { navLinks }
}
<script setup>
import { storeToRefs } from 'pinia'
import { useI18nStore } from '~/stores/i18n.js'

const i18nStore = useI18nStore()
const { locale } = storeToRefs(i18nStore)
const { setLocale } = i18nStore

function toggle() {
  setLocale(locale.value === 'fi' ? 'en' : 'fi')
}
</script>

<template>
  <button
    @click="toggle"
    class="px-2 py-1 rounded text-xs font-medium transition-colors duration-200 hover:bg-white/10"
    :style="{ color: 'var(--color-text-secondary)', border: '1px solid rgba(255,255,255,0.15)' }"
    :aria-label="locale === 'fi' ? 'Switch to English' : 'Vaihda suomeksi'"
  >
    {{ locale === 'fi' ? 'EN' : 'FI' }}
  </button>
</template>
<script setup>
import { ref } from 'vue'
import { useRouter } from 'vue-router'
import { useAuthStore } from '~/stores/auth.js'
import { useI18nStore } from '~/stores/i18n.js'
import { useNavLinks } from '~/composables/useNavLinks.js'
import ThemeToggle from './ThemeToggle.vue'
import LangToggle from './LangToggle.vue'

const { logout } = useAuthStore()
const { t } = useI18nStore()
const router = useRouter()
const menuOpen = ref(false)

async function handleLogout() {
  await logout()
  router.push('/login')
}

const { navLinks } = useNavLinks(handleLogout)

function toggleMenu() {
  menuOpen.value = !menuOpen.value
}

function closeMenu() {
  menuOpen.value = false
}

function handleDropdownKeydown(e) {
  if (e.key === 'Escape') {
    closeMenu()
  }
}
</script>

<template>
  <header
    class="sticky top-0 z-50"
    :style="{
      backgroundColor: 'var(--color-header-bg)',
      borderBottom: '2px solid var(--color-header-border)',
      paddingTop: 'env(safe-area-inset-top)',
    }"
  >
    <div class="px-6 h-16 flex justify-between items-center">
    <div class="flex gap-6 items-center">
      <NuxtLink to="/" class="!text-white text-2xl font-normal tracking-tight">erez.ac</NuxtLink>
    </div>

    <div class="flex items-center gap-2">
      <LangToggle />
      <ThemeToggle class="text-stone-400" />

      <!-- Hamburger — always visible -->
      <button
        class="p-2 text-stone-400 hover:text-white"
        @click="toggleMenu"
        :aria-label="t('nav.toggleMenu')"
        :aria-expanded="menuOpen"
      >
        <svg aria-hidden="true" xmlns="http://www.w3.org/2000/svg" class="size-6" fill="none" viewBox="0 0 24 24" stroke="currentColor" stroke-width="2">
          <path v-if="!menuOpen" stroke-linecap="round" stroke-linejoin="round" d="M4 6h16M4 12h16M4 18h16"/>
          <path v-else stroke-linecap="round" stroke-linejoin="round" d="M6 18L18 6M6 6l12 12"/>
        </svg>
      </button>
    </div>
    </div>

    <!-- Dropdown nav — universal (desktop + mobile) -->
    <nav
      v-if="menuOpen"
      class="absolute top-full right-0 flex flex-col py-2 shadow-lg rounded-bl-lg min-w-44"
      :style="{
        backgroundColor: 'var(--color-header-bg)',
        borderBottom: '2px solid var(--color-header-border)',
        borderLeft: '2px solid var(--color-header-border)'
      }"
      aria-label="Main"
      @keydown="handleDropdownKeydown"
    >
      <NuxtLink
        v-for="link in navLinks"
        :key="link.to"
        :to="link.action ? '' : link.to"
        class="!text-stone-400 px-6 py-3 text-sm transition-colors duration-200 hover:!text-accent hover:bg-white/10"
        @click.prevent="closeMenu(); link.action ? link.action() : router.push(link.to)"
      >
        {{ t(link.labelKey) }}
      </NuxtLink>
    </nav>
  </header>
</template>
<script setup>
import { useI18nStore } from '~/stores/i18n.js'

const { t } = useI18nStore()

defineProps({
  updateDate: { type: String, default: '' }
})
</script>

<template>
  <footer
    class="px-6 py-5"
    :style="{
      backgroundColor: 'var(--color-header-bg)',
      borderTop: '2px solid var(--color-header-border)',
    }"
  >
    <!-- Row 1: nav links -->
    <nav class="flex flex-wrap gap-x-5 gap-y-2 text-sm mb-3" aria-label="Footer">
      <NuxtLink to="/about" class="!text-stone-400 hover:!text-accent transition-colors">{{ t('nav.about') }}</NuxtLink>
      <NuxtLink to="/contact" class="!text-stone-400 hover:!text-accent transition-colors">{{ t('nav.contact') }}</NuxtLink>
      <NuxtLink to="/sanakenno" class="!text-stone-400 hover:!text-accent transition-colors">{{ t('nav.sanakenno') }}</NuxtLink>
    </nav>

    <!-- Row 2: last updated -->
    <div class="text-sm" style="color: var(--color-text-tertiary);">
      <span v-if="updateDate">{{ t('footer.lastUpdated', { date: updateDate }) }}</span>
    </div>
  </footer>
</template>
<script setup>
import { useI18nStore } from '~/stores/i18n.js'
import { useAuthStore } from '~/stores/auth.js'
import AppHeader from '~/components/AppHeader.vue'
import AppFooter from '~/components/AppFooter.vue'

const authStore = useAuthStore()
const { t } = useI18nStore()
const updateDate = ref('')
const routeAnnouncement = ref('')

const router = useRouter()
router.afterEach((to) => {
  const titleKey = to.meta.titleKey
  routeAnnouncement.value = titleKey ? t(titleKey) : 'erez.ac'
})

onMounted(async () => {
  authStore.checkAuth()
  try {
    const res = await fetch('/api/meta')
    const meta = await res.json()
    updateDate.value = meta.update_date
  } catch (e) {
    console.error('Failed to load meta:', e)
  }
})
</script>

<template>
  <a href="#main-content" class="skip-link">Skip to content</a>
  <div class="flex flex-col min-h-screen">
    <AppHeader />
    <main id="main-content" class="grow p-6" :style="{
      backgroundColor: 'var(--color-bg-primary)',
      color: 'var(--color-text-primary)',
    }">
      <slot />
    </main>
    <AppFooter :update-date="updateDate" />
  </div>
  <div aria-live="polite" aria-atomic="true" class="sr-only">{{ routeAnnouncement }}</div>
</template>
